#!/usr/bin/env bash

# This script tests the specific nix eval part from flake.nix by simulating its execution.
# It does NOT actually run 'nix eval' but simulates its inputs and expected output.

# --- Simulated Inputs (these would normally come from the Nix flake environment) ---
# flakePaths: A JSON array of .nix file paths.
# In a real scenario, this would be generated by pkgs.lib.filter and pkgs.lib.filesystem.listFilesRecursive.
SIMULATED_FLAKE_PATHS_JSON='["/simulated/path/to/flake1.nix", "/simulated/path/to/another/flake.nix"]'

# system: The system architecture.
SIMULATED_SYSTEM="aarch64-linux"

# nixpkgs: The path to the nixpkgs source.
SIMULATED_NIXPKGS_PATH="/simulated/path/to/nixpkgs"

# self.outPath: The output path of the current flake.
SIMULATED_SELF_OUT_PATH="/simulated/path/to/self-flake"

# get-nix-file-list: The path to the get-nix-file-list flake.
SIMULATED_GET_NIX_FILE_LIST_PATH="/simulated/path/to/get-nix-file-list-flake"

# --- Simulate the nix eval command ---
# The actual nix eval command from flake.nix is:
# ${pkgs.nix}/bin/nix eval --json --expr '''{ get-nix-file-list, pkgs, system, self, flakePaths }: ... getNixFileListFunc { inherit flakePaths; }''' \
#   --argstr flakePaths ${builtins.toJSON flakePaths} \
#   --argstr system "${system}" \
#   --arg pkgs ${nixpkgs} \
#   --arg self ${self.outPath} \
#   --arg get-nix-file-list ${get-nix-file-list} \
#   > nix-file-list.json

echo "Simulating nix eval command to generate nix-file-list.json..."

# Call the Nix expression to get the simulated output
nix eval --raw --expr "(import ./simulated-nix-eval.nix) { \
  flakePathsJson = \"$SIMULATED_FLAKE_PATHS_JSON\"; \
  system = \"$SIMULATED_SYSTEM\"; \
  nixpkgsPath = \"$SIMULATED_NIXPKGS_PATH\"; \
  selfOutPath = \"$SIMULATED_SELF_OUT_PATH\"; \
  getNixFileListPath = \"$SIMULATED_GET_NIX_FILE_LIST_PATH\"; \
}" > nix-file-list.json

echo "Generated nix-file-list.json content:"
cat nix-file-list.json

echo "Test complete. The nix-file-list.json file has been created with simulated content."
